+export function createSandboxedWriteTool(root: string) {
+  const base = createWriteTool(root) as unknown as AnyAgentTool;
+  return wrapSandboxPathGuard(
+    wrapToolParamNormalization(base, CLAUDE_PARAM_GROUPS.write),
