+
+export function createSandboxedEditTool(root: string) {
+  const base = createEditTool(root) as unknown as AnyAgentTool;
+  return wrapSandboxPathGuard(
+    wrapToolParamNormalization(base, CLAUDE_PARAM_GROUPS.edit),
